def search_users(
    username: Optional[str] = None,
    email: Optional[str] = None,
    role: Optional[str] = None,
    status: Optional[str] = None,
) -> List[Dict[str, Any]]:
    """
    Fetch user profiles from PostgreSQL based on multiple filter criteria.

    Supports filtering by any combination of:
        - username (partial match, case-insensitive)
        - email (exact match, case-insensitive)
        - role ('admin', 'user', 'guest')
        - status ('active', 'suspended')

    All queries use parameterized statements to prevent SQL injection.

    Args:
        username: Filter by username (partial match via ILIKE).
        email: Filter by exact email address (case-insensitive).
        role: Filter by role. Must be one of 'admin', 'user', 'guest'.
        status: Filter by account status. Must be 'active' or 'suspended'.

    Returns:
        A list of dictionaries, each representing a user profile.

    Raises:
        ValueError: If an invalid role or status is provided.
    """
    if role is not None and role not in VALID_ROLES:
        raise ValueError(f"Invalid role '{role}'. Must be one of: {VALID_ROLES}")
    if status is not None and status not in VALID_STATUSES:
        raise ValueError(f"Invalid status '{status}'. Must be one of: {VALID_STATUSES}")

    base_query = "SELECT id, username, email, role, status, created_at, updated_at FROM users"
